const item = $input.first().json;
const { runId, data, schema, stageName } = item;

if (!data) return [{ json: { runId, valid: false, errors: ['No data provided'], stageName } }];
if (!schema) return [{ json: { runId, valid: true, errors: [], stageName, data } }];

const errors = [];

// Simple required field validation
const checkRequired = (obj, fields, prefix = '') => {
  fields.forEach(field => {
    if (obj[field] === undefined || obj[field] === null) {
      errors.push(`Missing required field: ${prefix}${field}`);
    }
  });
};

// Check top-level required fields
if (schema.required) {
  checkRequired(data, schema.required);
}

// Check array fields are actually arrays
if (schema.arrays) {
  schema.arrays.forEach(field => {
    if (data[field] !== undefined && !Array.isArray(data[field])) {
      errors.push(`Field '${field}' must be an array`);
    }
  });
}

// Check string fields
if (schema.strings) {
  schema.strings.forEach(field => {
    if (data[field] !== undefined && typeof data[field] !== 'string') {
      errors.push(`Field '${field}' must be a string`);
    }
  });
}

console.log(`[SUB_Validate_JSON_Schema][${runId}][${stageName}] Validation: ${errors.length === 0 ? 'PASS' : 'FAIL'} (${errors.length} errors)`);

return [{
  json: {
    runId,
    stageName,
    valid: errors.length === 0,
    errors,
    data: errors.length === 0 ? data : null
  }
}];
